  OnInput(event: any, flag) {
    if(flag){
      this.salary = event.target.value;  
    } else {
      this.salary = event;
    }
      
    console.log("this.salary)::",this.salary);
    let sal = this.salary.toString().replace(/,/g, '').split(".");
    sal[0] = sal[0].replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    let final = sal.join(".");
    console.log("final",final);
    this.emp.controls.salary.setValue(final);
  }
  
