  aadharParser = (str) => {
    try {
      let adharNumber,
        dob,
        name,
        nameLineIndex = 2;
      const asciiStr = str.replace(/[^\x00-\x7F]/g, "").trim();
      const lines = asciiStr.split("\n");
  
      for (let i = lines.length - 1; i >= 0; i--) {
        let count = 0,
          startIndex = -1;
        for (let j = 0; j < lines[i].length; j++) {
          if (lines[i][j] >= "0" && lines[i][j] <= "9") {
            count++;
            if (startIndex === -1) startIndex = j;
          }
        }
        if (count >= 12) {
          adharNumber = lines[i].substr(startIndex, startIndex + 14);
        }
      }
  
      for (let i = 0; i < lines.length; i++) {
        ["DOB", "Year of Birth"].some((docString) => {
          const dobIndex = lines[i].indexOf(docString);
          if (dobIndex !== -1) {
            dob = lines[i]
              .trim()
              .slice(dobIndex, lines[i].length)
              .split(" ")
              .pop();
            nameLineIndex = i - 1;
            console.log(dob);
          }
        });
      }
  
      const names = lines[nameLineIndex]
        .split(" ")
        .filter((x) => x.length > 1)
        .join(" ");
      console.log(names);
      return {
        dob,
        adharNumber,
        fullName: names,
      };
    } catch (error) {
      console.log(error);
      console.error("Unable to parse aadhar");
    }
  };
  
