  panCardParser = (str) => {
    try {
      const asciiStr = str.replace(/[^\x00-\x7F]/g, "");
      const startIndex = asciiStr.indexOf("Permanent");
      const nameIndex = asciiStr.indexOf("Name");
  
      const panNumber = asciiStr.slice(startIndex, nameIndex).match("[A-Z]{5}[0-9]{4}[A-Z]{1}")[0]; // Returns ain,ain,ain
  
      const fatherNameIndex = asciiStr.indexOf("Father's Name :");
      //const slicedStr = asciiStr.slice(fatherNameIndex, str.length).split('\n');
  
      const nameString = asciiStr.slice(nameIndex, fatherNameIndex).split("\n"); // .find(str => str.length > 3);
      const displayName = nameString[1].split(" ");
      const dobString = asciiStr.slice(asciiStr.indexOf("Date of Birth"), asciiStr.length);
      const dob = dobString.split("\n")[1].split(" ")[0];
      return {
          panNumber,
          name: `${displayName[0]} ${displayName[1]}`,
          dateOfBirth: dob
  
      }
    } catch (error) {
        console.log(error);
      console.error("Unable to parse pan card");
    }
  };

  passportParser = (str) => {
    try {
      let dateOfIssue, dateOfExpiry;
      const asciiStr = str.replace(/[^\x00-\x7F]/g, "");
      const nameIndex = asciiStr.indexOf("Given Name");
  
      const lines = asciiStr.slice(nameIndex, asciiStr.length).split("\n");
      const doIssueIndex =
        lines.findIndex((line) => line.indexOf("Date of Issue") > -1) + 1;
      if (doIssueIndex > 0) {
        console.log(lines[doIssueIndex]);
        const dates = lines[doIssueIndex].split(" ");
        dateOfIssue = dates[dates.length - 2];
        dateOfExpiry = dates[dates.length - 2];
      }
  
      const nationalityIndex = asciiStr.indexOf("Nationality");
      const dob = asciiStr
        .slice(nationalityIndex, asciiStr.length)
        ?.split("\n")[1]
        .split(" ")
        .pop();
  
      let issueNoString;
      const issueNoStringArray = asciiStr.trim().split("\n");
      for (let i = issueNoStringArray.length - 1; i >= 0; i--) {
        if (issueNoStringArray[i].includes("<")) {
          issueNoString = issueNoStringArray[i].substr(
            0,
            issueNoStringArray[i].indexOf("<")
          );
          break;
        }
      }
  
      return {
        dob,
        name: lines[1],
        issueNoString,
        dateOfIssue,
        dateOfExpiry,
      };
    } catch (error) {
      console.error("Unable to parse passport");
    }
  };


