  onUpload(event, docVal, docSideEnum) {
    console.log(event, docVal, docSideEnum);
    if (docVal === 'frontSide') {
      this.progressValFront=0;
    }
    if (docVal === 'backSide') {
      this.progressValBack=0;
    }
    if (docVal === 'others') {
      this.progressValOthers=0;
    }
    this.selectedFiles = event.target.files[0];
    let size = event.target.files[0].size;
    this.shotToast(`Your file size is ${this.formatBytes(size, 2)}`);
    if (event.target.files) {
      var reader = new FileReader();
      reader.readAsDataURL(event.target.files[0]);
      reader.onload = (event: any) => {
        this.image = event.target.result;

        if (docVal === 'backSide') {
          this.backSelected = this.selectedFiles.name;
          this.imageURL1 = this.image;
           this.doOCR(this.imageURL1,docVal, this.selectedFiles, docSideEnum);
          console.log("Called after ocr");
          this.displayVal1 = true;
        }

        if (docVal === 'frontSide') {
          this.frontSelected = this.selectedFiles.name;
          this.imageURL = this.image;
          this.doOCR(this.imageURL,docVal, this.selectedFiles, docSideEnum);
          console.log("Called after ocr");
          this.displayVal = true;
        }

        if (docVal === 'others') {
          this.othersSelected = this.selectedFiles.name;
          this.imageURL2 = this.image;
           this.doOCR(this.imageURL2,docVal, this.selectedFiles, docSideEnum);
          console.log("Called after ocr");
          this.displayVal2 = true;
          // this.documentSide = 1;
        }
      }
    }
    // this.uploadDoc(event.target.files[0], this.selectedFiles, docVal, docSideEnum);
    // if(size > 1048576){
    //   this.shotToast(`Your file size is ${this.formatBytes(size,2)}, Kindly Upload below ${this.formatBytes(1048576,2)} file size`);
    // }
    this.disableNext = false;
  }


  formatBytes(bytes, decimals) {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
  }

  uploadDoc(url, docVal, documnetSideValue) {
    console.log("URL ---- ", url);
    const cId: string = this.customerId;
    const uploadData = new FormData();
    console.log("cId::", this.refreshCustomerId);
    const data = {
      customerId: this.refreshCustomerId,
      documentName: this.documentForm.value.documentName,
      documentType: "3",
      fileType: url.type,
      fileName: url.name,
      verificationType: "KYC verification",
      documentSide: documnetSideValue,
      idNumber : this.panNumber,
      name : this.namePancard,
      dob : this.dob
    };
    uploadData.append("data", JSON.stringify(data));
    uploadData.append("file", url);
    console.log("URL -- ", url.name);
    console.log('data :: ',data);
    this.uploadSub = this.tokenService.upload(uploadData)
      .subscribe((res: any) => {
      
        console.log("Response -- ", res);
        if (docVal === 'backSide') {
          if(res.type){
          if (res.type == HttpEventType.UploadProgress) {
            this.progressValBack = Math.round(100 * (res.loaded / res.total));
            console.log("uploadProgress", this.progressValBack);
          } 
          // else if (res.type == HttpEventType.Response) {
          //   this.progressValBack = 0;
          // }
        }
        } else if ((docVal === 'frontSide')) {
          if(res.type){
          if (res.type == HttpEventType.UploadProgress) {
            this.progressValFront = Math.round(100 * (res.loaded / res.total));
            console.log("uploadProgress", this.progressValFront);
          } 
          // else if (res.type == HttpEventType.Response) {
          //   this.progressValFront = 0;
          // }
        }
        }
        else if ((docVal === 'others')) {
          if(res.type){
          if (res.type == HttpEventType.UploadProgress) {
            this.progressValOthers = Math.round(100 * (res.loaded / res.total));
            console.log("uploadProgress others", this.progressValOthers);
           }}
            // else if (res.type == HttpEventType.Response) {
          //   this.progressValOthers = 0;
          // }
        }
        if(res.body) {
        
          console.log("res.body.id",res.body.id);
          this.assignIdValues(docVal,res.body.id);
          this.documentForm.get(docVal).patchValue(true);
          this.shotToast("Document Uploaded!");

        }
      },
        (error: any) => {
         
          console.log("File upload ::", error);
          if (error.status == 201) {
            this.documentForm.get(docVal).patchValue(true);
            this.shotToast("Document Uploaded!");
          } else {
            if (docVal === 'backSide') {
              this.progressValBack = 0;
              this.imageURL1 = null;
              this.backSelected = null;
              this.shotToast(error.message);
            } else {
              this.progressValFront = 0;
              this.imageURL = null;
              this.frontSelected = null;
              this.shotToast(error.message);
            }
          }
        }
        
      );
      
  }
  assignIdValues(docVal: any, id: any) {
    if(docVal === 'backSide')
    {
     
      this.backSideId=id;
    }
    if (docVal === 'others'){
      this.otherSideId=id;
    }
  }

