import { Component, Inject, Input, OnInit, Output, ViewChild } from '@angular/core';
import { FormArray, FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { MatDialog, MatDialogConfig, MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';
import { MatTabChangeEvent, MatTabGroup } from '@angular/material/tabs';
import { Router } from '@angular/router';
import { ApiService } from 'app/shared/services/api.service';
// import { ApiService } from 'app/api.service';
import { Observable } from 'rxjs';
import { FingerprintAuthenticationComponent } from '../fingerprint-authentication/fingerprint-authentication.component';

@Component({
  selector: 'app-kyc-screening',
  templateUrl: './kyc-screening.component.html',
  styleUrls: ['./kyc-screening.component.scss']
})
export class KycScreeningComponent implements OnInit {
  @ViewChild('tabGroup', { static: false }) tabGroup: MatTabGroup;
  basicInformationForm: FormGroup;
  basicInformationFlag: boolean = true;
  documentsFlag: boolean;
  a = 20;
  @Input() titleName: any = 'kyc';
  animal: string;
  name: string = 'kannan';
  selectedOption = 'option1'
  otpmodel = new OtpModel();
  indexList: string[];
  dropVariable: string;
  basic: boolean = true;
  verificationFlag: boolean;
  tabIndex: Number;
  masterInfo: any = {};
  tab1: boolean;
  tab2: boolean;
  tab3: boolean;
  finish: any;
  finishFlag: boolean=true;

  constructor(private api: ApiService, public dialog: MatDialog, private router: Router, private fb: FormBuilder) { }

  ngOnInit(): void {
    this.api.getIndex().subscribe(resp => {
      console.log(resp.index)
      this.tabIndex = resp.index;
      this.api.getFinishFlag().subscribe(resp=>{
        console.log("finish flag",resp.finishFlag);
        this.assignValueFinish(resp.finishFlag)
      })
      if (resp.index === 0) {
        this.assignValuesForTab2(this.tabIndex);
      }
      if (resp.index === 1) {
        this.assignValuesForTab2(this.tabIndex);
      }
      if (resp.index === 2) {
        this.assignValuesForTab3(this.tabIndex);
      }
      // TODO WITH MATTAB DISABLE CUSTOM LATER
      // this.tabGroup._tabs[resp.index].disabled = true;
    
    })
  }
  assignValueFinish(finishFlag) {
    this.finishFlag=finishFlag;
  }

  assignValuesForTab1(tabIndex) {
    this.tab1 = false;
  
  }

  assignValuesForTab2(tabIndex) {
    this.tab2 = false;
  
  }

  assignValuesForTab3(tabIndex) {
    this.tab3 = false;
    
  }

  basicInformation() {
    this.basicInformationFlag = true;
  }

  verification() {
    this.router.navigateByUrl('/others/verification');
  }

  openDialog() {
    this.titleName = '9656849771'
    const dialogRef = this.dialog.open(FingerprintAuthenticationComponent);
  }
  openDialog1() {
    const dialogRef = this.dialog.open(FingerprintAuthenticationComponent, { data: { number: '9656849771', type: 'Mobile Number' }, disableClose: true });
    dialogRef.afterClosed().subscribe((submit) => {
      // if (submit) {
      //   this.food = submit;
      // } else {
      //   this.food = 'Nothing...';
      // }
    })
  }


  openDialogEmail(email) {

    const dialogRef = this.dialog.open(FingerprintAuthenticationComponent, { data: { number: email, type: 'email id' }, disableClose: true });
    dialogRef.afterClosed().subscribe((submit) => {
      // if (submit) {
      //   this.food = submit;
      // } else {
      //   this.food = 'Nothing...';
      // }
    })
  }
  documents() {
    console.log("enter inside")
    // this.router.navigateByUrl('/others/documents');
    this.basicInformationFlag = false;
    this.documentsFlag = true;
  }
  tabClick(event: MatTabChangeEvent) {

    const tab = event.tab.textLabel;
    console.log(tab);

    if (tab === "Documents Upload") {
      this.basic = false;
      this.documentsFlag = true;
      this.verificationFlag = false;

      //  this.documents();
      //  this.router.navigateByUrl('/others/documents');
    }
    if (tab === "verification") {
      this.basic = false;
      this.documentsFlag = false;
      this.verificationFlag = true;
      // this.router.navigateByUrl('/others/verification');
    }
    if (tab === "Basic Information") {
      this.basic = true;
      this.documentsFlag = false;
      this.verificationFlag = false;
      //  this.router.navigateByUrl('/others/kyc');
    }
  }

  verify() {
    this.router.navigateByUrl('/others/verification');
    console.log("enter inside verify method")
    // this.basicInformationFlag=false;
  }
  onNext(basicInformationForm) {
    this.api.setNewUserInfo({
      prefix: basicInformationForm.prefix,
      firstName: basicInformationForm.firstName,
      lastName: basicInformationForm.lastName,
      primaryEmailAdress: basicInformationForm.primaryEmailAdress,
      phoneNumber: basicInformationForm.phoneNumber,
    });


    console.log("value of basicInformationForm", basicInformationForm)
    this.api.kycScreenBasicinfo(basicInformationForm).subscribe(resp => {
      console.log("resp after saving basic info", resp)
      console.log('customer_id', resp.customerId)
      sessionStorage.setItem('customer_id', resp.customerId);
      console.log('customer_id', resp.customerId)

    })
  }
  getOtp(email) {
    console.log(email.primaryEmail);
    this.otpmodel.source = 'customer';
    this.otpmodel.source_key = 'email';
    this.otpmodel.source_value = email.primaryEmail;
    console.log("model", this.otpmodel);
    console.log("service for Api call");

    this.api.getOtp(this.otpmodel).subscribe(resp => {


    })
    this.openDialogEmail(email.primaryEmail);
  }

  getPrefix() {
    this.dropVariable = 'prefix';
    this.api.getDropDownValues(this.dropVariable).subscribe(data => {
      this.indexList = data;
    });
  }

}

export interface DialogData {
  animal: 'panda';
}

export class OtpModel {
  source_key: any;
  source_value: any;
  source: any;
}